import{createRoot as domCreateRoot,hydrateRoot as domHydrateRoot}from"react-dom/client";import{createSheet}from"../StyleSheet/dom";function hydrate(e,t){return createSheet(t),domHydrateRoot(t,e)}export default function render(e,t){createSheet(t);t=domCreateRoot(t);return t.render(e),t}export{hydrate};